            choice = input("\nEnter your choice (1-4): ").strip()
            
            if choice == '4':
                print("Exiting...")
                break
            
            if choice not in ['1', '2', '3']:
                print("Invalid choice. Please try again.")
                continue
            
            file_path = input("Enter the full path to the data file: ").strip()
            table_name = input("Enter the target table name: ").strip()
            
            if choice == '1':
                field_delimiter = ','
                line_delimiter = '\n'
            elif choice == '2':
                field_delimiter = '\t'
                line_delimiter = '\n'
            else:
                field_delimiter = input("Enter field delimiter (default ','): ").strip() or ','
                line_delimiter = input("Enter line delimiter (default '\\n'): ").strip() or '\n'
                if line_delimiter == '\\n':
                    line_delimiter = '\n'
                elif line_delimiter == '\\r\\n':
                    line_delimiter = '\r\n'
            
            ignore_lines_input = input("Number of header lines to ignore (default 1): ").strip()
            ignore_lines = int(ignore_lines_input) if ignore_lines_input else 1
            
            print(f"\nImporting data from: {file_path}")
